  1→import { createContext, useContext, useReducer, useCallback } from 'react';
  2→import { createSketchProject, createLayer } from '../domain/sketchModels';
  3→
  4→const SketchContext = createContext(null);
  5→const HISTORY_LIMIT = 80;
  6→
  7→function snapshotSketch(sketchProject) {
  8→  return JSON.stringify(sketchProject);
  9→}
 10→
 11→function applyUpdate(state, nextProject, recordHistory = true) {
 12→  const nextSnapshot = snapshotSketch(nextProject);
 13→  const history = recordHistory
 14→    ? [...state.history, state.project].slice(-HISTORY_LIMIT)
 15→    : state.history;
 16→
 17→  return {
 18→    ...state,
 19→    history,
 20→    future: recordHistory ? [] : state.future,
 21→    project: nextProject,
 22→    isDirty: nextSnapshot !== state.savedSnapshot,
 23→  };
 24→}
 25→
 26→function updateLayer(state, layerId, updater) {
 27→  const nextLayers = state.project.layers.map((layer) =>
 28→    layer.id === layerId ? updater(layer) : layer
 29→  );
 30→  return applyUpdate(state, {
 31→    ...state.project,
 32→    updatedAt: new Date().toISOString(),
 33→    layers: nextLayers,
 34→  });
 35→}
 36→
 37→function sketchReducer(state, action) {
 38→  switch (action.type) {
 39→    case 'SKETCH_NEW': {
 40→      const newProject = action.project || createSketchProject();
 41→      return {
 42→        project: newProject,
 43→        isDirty: false,
 44→        savedSnapshot: snapshotSketch(newProject),
 45→        history: [],
 46→        future: [],
 47→      };
 48→    }
 49→
 50→    case 'SKETCH_LOAD': {
 51→      const loaded = action.project;
 52→      return {
 53→        project: loaded,
 54→        isDirty: false,
 55→        savedSnapshot: snapshotSketch(loaded),
 56→        history: [],
 57→        future: [],
 58→      };
 59→    }
 60→
 61→    case 'LAYER_ADD': {
 62→      const newLayer = action.layer || createLayer();
 63→      return applyUpdate(state, {
 64→        ...state.project,
 65→        updatedAt: new Date().toISOString(),
 66→        layers: [...state.project.layers, newLayer],
 67→      });
 68→    }
 69→
 70→    case 'LAYER_UPDATE':
 71→      return applyUpdate(state, {
 72→        ...state.project,
 73→        updatedAt: new Date().toISOString(),
 74→        layers: state.project.layers.map((layer) =>
 75→          layer.id === action.layer.id ? { ...layer, ...action.layer } : layer
 76→        ),
 77→      });
 78→
 79→    case 'LAYER_DELETE': {
 80→      if (state.project.layers.length <= 1) return state;
 81→      return applyUpdate(state, {
 82→        ...state.project,
 83→        updatedAt: new Date().toISOString(),
 84→        layers: state.project.layers.filter((layer) => layer.id !== action.layerId),
 85→      });
 86→    }
 87→
 88→    case 'LAYER_REORDER':
 89→      return applyUpdate(state, {
 90→        ...state.project,
 91→        updatedAt: new Date().toISOString(),
 92→        layers: action.layers,
 93→      });
 94→
 95→    case 'SHAPE_ADD':
 96→      return updateLayer(state, action.layerId, (layer) => ({
 97→        ...layer,
 98→        shapes: [...layer.shapes, action.shape],
 99→      }));
100→
101→    case 'SHAPE_UPDATE':
102→      return updateLayer(state, action.layerId, (layer) => ({
103→        ...layer,
104→        shapes: layer.shapes.map((shape) =>
105→          shape.id === action.shape.id ? { ...shape, ...action.shape } : shape
106→        ),
107→      }));
108→
109→    case 'SHAPE_DELETE':
110→      return updateLayer(state, action.layerId, (layer) => ({
111→        ...layer,
112→        shapes: layer.shapes.filter((shape) => shape.id !== action.shapeId),
113→      }));
114→
115→    case 'OBJECT_ADD':
116→      return applyUpdate(state, {
117→        ...state.project,
118→        updatedAt: new Date().toISOString(),
119→        objects: [...(state.project.objects || []), action.object],
120→      });
121→
122→    case 'OBJECT_UPDATE':
123→      return applyUpdate(state, {
124→        ...state.project,
125→        updatedAt: new Date().toISOString(),
126→        objects: (state.project.objects || []).map((obj) =>
127→          obj.id === action.object.id ? { ...obj, ...action.object } : obj
128→        ),
129→      });
130→
131→    case 'OBJECT_DELETE':
132→      return applyUpdate(state, {
133→        ...state.project,
134→        updatedAt: new Date().toISOString(),
135→        objects: (state.project.objects || []).filter((obj) => obj.id !== action.objectId),
136→      });
137→
138→    case 'ANNOTATION_ADD':
139→      return applyUpdate(state, {
140→        ...state.project,
141→        updatedAt: new Date().toISOString(),
142→        annotations: [...(state.project.annotations || []), action.annotation],
143→      });
144→
145→    case 'ANNOTATION_UPDATE':
146→      return applyUpdate(state, {
147→        ...state.project,
148→        updatedAt: new Date().toISOString(),
149→        annotations: (state.project.annotations || []).map((a) =>
150→          a.id === action.annotation.id ? { ...a, ...action.annotation } : a
151→        ),
152→      });
153→
154→    case 'ANNOTATION_DELETE':
155→      return applyUpdate(state, {
156→        ...state.project,
157→        updatedAt: new Date().toISOString(),
158→        annotations: (state.project.annotations || []).filter((a) => a.id !== action.annotationId),
159→      });
160→
161→    case 'PROJECT_UPDATE_META':
162→      return applyUpdate(state, {
163→        ...state.project,
164→        updatedAt: new Date().toISOString(),
165→        ...action.meta,
166→      });
167→
168→    case 'UNDO': {
169→      if (state.history.length === 0) return state;
170→      const previous = state.history[state.history.length - 1];
171→      return {
172→        ...state,
173→        project: previous,
174→        history: state.history.slice(0, -1),
175→        future: [state.project, ...state.future].slice(0, HISTORY_LIMIT),
176→        isDirty: snapshotSketch(previous) !== state.savedSnapshot,
177→      };
178→    }
179→
180→    case 'REDO': {
181→      if (state.future.length === 0) return state;
182→      const next = state.future[0];
183→      return {
184→        ...state,
185→        project: next,
186→        history: [...state.history, state.project].slice(-HISTORY_LIMIT),
187→        future: state.future.slice(1),
188→        isDirty: snapshotSketch(next) !== state.savedSnapshot,
189→      };
190→    }
191→
192→    case 'MARK_SAVED':
193→      return {
194→        ...state,
195→        isDirty: false,
196→        savedSnapshot: snapshotSketch(state.project),
197→      };
198→
199→    default:
200→      return state;
201→  }
202→}
203→
204→function createInitialState(project) {
205→  return {
206→    project,
207→    isDirty: false,
208→    savedSnapshot: snapshotSketch(project),
209→    history: [],
210→    future: [],
211→  };
212→}
213→
214→export function SketchProvider({ children, initialProject }) {
215→  const [state, dispatch] = useReducer(
216→    sketchReducer,
217→    initialProject || createSketchProject(),
218→    createInitialState
219→  );
220→
221→  return (
222→    <SketchContext.Provider value={{ state, dispatch }}>
223→      {children}
224→    </SketchContext.Provider>
225→  );
226→}
227→
228→export function useSketch() {
229→  const ctx = useContext(SketchContext);
230→  if (!ctx) throw new Error('useSketch must be used within SketchProvider');
231→  const { state, dispatch } = ctx;
232→
233→  const getObject = useCallback(
234→    (objectId) => (state.project.objects || []).find((o) => o.id === objectId) || null,
235→    [state.project.objects]
236→  );
237→
238→  const getShapesForObject = useCallback(
239→    (objectId) => {
240→      const obj = (state.project.objects || []).find((o) => o.id === objectId);
241→      if (!obj) return [];
242→      const idSet = new Set(obj.shapeIds);
243→      const result = [];
244→      for (const layer of state.project.layers) {
245→        for (const shape of layer.shapes) {
246→          if (idSet.has(shape.id)) result.push(shape);
247→        }
248→      }
249→      return result;
250→    },
251→    [state.project.objects, state.project.layers]
252→  );
253→
254→  return {
255→    project: state.project,
256→    isDirty: state.isDirty,
257→    canUndo: state.history.length > 0,
258→    canRedo: state.future.length > 0,
259→    dispatch,
260→    getLayer: (layerId) => state.project.layers.find((l) => l.id === layerId) || null,
261→    getObject,
262→    getShapesForObject,
263→  };
264→}
