export const SKETCH_TOOLS = {
  SELECT: 'select',
  RECTANGLE: 'rectangle',
  ELLIPSE: 'ellipse',
  LINE: 'line',
  PEN: 'pen',
};

export const DEFAULT_SKETCH_ZOOM = 0.15;
export const DEFAULT_CANVAS_WIDTH = 297000;
export const DEFAULT_CANVAS_HEIGHT = 210000;

export const SKETCH_MIN_ZOOM = 0.02;
export const SKETCH_MAX_ZOOM = 3.0;
export const SKETCH_ZOOM_FACTOR = 1.1;

export const SKETCH_GRID_MINOR = 50;   // mm
export const SKETCH_GRID_MAJOR = 1000; // mm

export const SKETCH_SNAP_DISTANCE_PX = 8;

export const SKETCH_OBJECT_CATEGORIES = [
  'table', 'chair', 'desk', 'cabinet', 'shelf', 'bed', 'sofa', 'general',
];

import { createSketchObject, createShape } from './sketchModels';

export function buildDemoTable(layerId) {
  const object = createSketchObject('Office Desk', 'table');

  // Tabletop: 1200mm x 600mm, centered at origin area
  const tabletop = createShape('rect', {
    layerId,
    x: 50000,
    y: 50000,
    width: 120000,
    height: 60000,
    fill: 'rgba(184, 134, 11, 0.06)',
    stroke: '#1E2433',
    strokeWidth: 2,
  });

  // Leg dimensions
  const legW = 4000;
  const legH = 4000;
  const inset = 3000;

  const topLeft = createShape('rect', {
    layerId,
    x: 50000 + inset,
    y: 50000 + inset,
    width: legW,
    height: legH,
    fill: '#1E2433',
    stroke: '#1E2433',
    strokeWidth: 1,
  });

  const topRight = createShape('rect', {
    layerId,
    x: 50000 + 120000 - inset - legW,
    y: 50000 + inset,
    width: legW,
    height: legH,
    fill: '#1E2433',
    stroke: '#1E2433',
    strokeWidth: 1,
  });

  const bottomLeft = createShape('rect', {
    layerId,
    x: 50000 + inset,
    y: 50000 + 60000 - inset - legH,
    width: legW,
    height: legH,
    fill: '#1E2433',
    stroke: '#1E2433',
    strokeWidth: 1,
  });

  const bottomRight = createShape('rect', {
    layerId,
    x: 50000 + 120000 - inset - legW,
    y: 50000 + 60000 - inset - legH,
    width: legW,
    height: legH,
    fill: '#1E2433',
    stroke: '#1E2433',
    strokeWidth: 1,
  });

  const shapes = [tabletop, topLeft, topRight, bottomLeft, bottomRight];
  object.shapeIds = shapes.map((s) => s.id);

  return { object, shapes };
}

