 21→  const [walkUiState, setWalkUiState] = useState({
 22→    navigationMode: 'inspect',
 23→    isLocked: false,
 24→    canLock: false,
 25→  });
 26→  const { selectedId, selectedType, activePhaseId, phaseViewMode, dispatch: editorDispatch } = useEditor();
 27→
 28→  const filteredProject = useMemo(
 29→    () => filterProjectByPhase(project, activePhaseId, phaseViewMode),
 30→    [project, activePhaseId, phaseViewMode]
 31→  );
