        selectedType: null,
      };

    case 'SELECT_OBJECT':
      return {
        ...state,
        selectedId: action.id,
        selectedType: action.objectType,
      };

    case 'DESELECT':
      return {
        ...state,
        selectedId: null,
        selectedType: null,
      };

    case 'UPDATE_TOOL_STATE':
      return {
        ...state,
        toolState: { ...state.toolState, ...action.payload },
      };

    case 'SET_VIEWPORT':
      return {
        ...state,
        viewport: { ...action.viewport },
      };

    case 'PAN':
      return {
        ...state,
        viewport: {
          ...state.viewport,
          panX: state.viewport.panX + action.dx,
          panY: state.viewport.panY + action.dy,
        },
      };

    case 'ZOOM': {
      const { zoom, panX, panY } = action;
      return {
        ...state,
        viewport: { zoom, panX, panY },
      };
    }

    case 'SET_VIEW':
      return {
        ...state,
        activeView: action.view,
      };

    case 'SET_ACTIVE_ASSEMBLY':
      return {
        ...state,
        activeAssemblyId: action.assemblyId,
      };

    case 'TOGGLE_GRID':
