    onMouseMove() {},

    onMouseUp() {},

    onKeyDown(e) {
      if (e.key === 'Escape') {
        editorDispatch({
          type: 'UPDATE_TOOL_STATE',
          payload: { firstPoint: null },
        });
      }
    },

    getCursor() {
      return 'crosshair';
    },
  };
}

