207→  const dimensions = project.parts.filter((p) => p.type === 'dimension');
208→
209→  // Drag preview for part placement
210→  const drawPreview = toolState.drawing && toolState.startPos && toolState.currentPos
211→    ? {
212→        x: Math.min(toolState.startPos.x, toolState.currentPos.x),
213→        y: Math.min(toolState.startPos.y, toolState.currentPos.y),
214→        width: Math.abs(toolState.currentPos.x - toolState.startPos.x),
215→        height: Math.abs(toolState.currentPos.y - toolState.startPos.y),
216→      }
217→    : null;
218→
219→  // Dimension first-click indicator
220→  const dimFirstClick = activeTool === 'dimension' && toolState.firstPoint;
221→
222→  // Compute XYZ from cursor position using inverse projection
223→  const modelXYZ = viewToModelPosition(cursorPos.x, cursorPos.y, activeView);
224→
225→  return (
226→    <div className={styles.canvasContainer}>
227→      <svg
228→        ref={svgRef}
229→        className={styles.svg}
230→        style={{ cursor }}
231→        onPointerDown={handleMouseDown}
232→        onPointerMove={handleMouseMove}
233→        onPointerUp={handleMouseUp}
234→      >
235→        <g transform={`translate(${viewport.panX}, ${viewport.panY}) scale(${viewport.zoom})`}>
236→          {showGrid && <GridRenderer />}
237→
238→          {/* Canvas boundary indicator */}
239→          <rect
240→            x={0}
241→            y={0}
242→            width={project.canvasWidth}
243→            height={project.canvasHeight}
244→            fill="none"
245→            stroke="var(--color-border)"
246→            strokeWidth={2}
247→            vectorEffect="non-scaling-stroke"
248→            strokeDasharray="8 4"
249→            style={{ pointerEvents: 'none' }}
250→          />
251→
252→          {/* Rendered parts */}
253→          {renderParts.map((part) => (
254→            <PartRenderer
255→              key={part.id}
256→              part={part}
257→              view={activeView}
258→              isSelected={part.id === selectedId}
259→              zoom={viewport.zoom}
260→            />
261→          ))}
262→
263→          {/* Dimension annotations */}
264→          {dimensions.map((dim) => (
265→            <DimensionRenderer
266→              key={dim.id}
267→              dimension={dim}
268→              view={activeView}
269→              zoom={viewport.zoom}
270→            />
271→          ))}
272→
273→          {/* Draw preview */}
274→          {drawPreview && (
275→            <rect
276→              x={drawPreview.x}
277→              y={drawPreview.y}
278→              width={drawPreview.width}
279→              height={drawPreview.height}
280→              fill="none"
281→              stroke="var(--color-workspace-sketch, #B8860B)"
282→              strokeWidth={2}
283→              vectorEffect="non-scaling-stroke"
284→              strokeDasharray="6 3"
285→              style={{ pointerEvents: 'none' }}
286→            />
287→          )}
288→
289→          {/* Dimension first-click indicator */}
290→          {dimFirstClick && (
291→            <circle
292→              cx={toolState.firstPoint.x}
293→              cy={toolState.firstPoint.y}
294→              r={5 / viewport.zoom}
295→              fill="var(--color-workspace-sketch, #B8860B)"
296→              style={{ pointerEvents: 'none' }}
297→            />
298→          )}
299→        </g>
300→      </svg>
301→
302→      {/* Empty-state overlay */}
303→      {showEmptyState && <SketchEmptyState />}
304→
305→      {/* Status bar */}
306→      <div className={styles.statusBar} role="status" aria-live="polite">
307→        <span className={styles.statusContext}>{getViewLabel(activeView)}</span>
308→        <span className={styles.statusCoords}>X: {Math.round(modelXYZ.x)} mm</span>
309→        <span className={styles.statusCoords}>Y: {Math.round(modelXYZ.y)} mm</span>
310→        <span className={styles.statusCoords}>Z: {Math.round(modelXYZ.z)} mm</span>
311→        <span className={styles.statusContext}>Zoom: {zoomPercent}%</span>
312→        <span className={styles.statusTool}>{activeTool}</span>
313→      </div>
314→
315→      {/* Toast notifications */}
316→      {statusMessage && (
317→        <div className={styles.toast}>
318→          {statusMessage}
319→          <div className={styles.toastProgress} />
320→        </div>
321→      )}
322→    </div>
323→  );
324→}
