 1→const INDEX_KEY = 'sketch-planner-projects';
 2→const PROJECT_PREFIX = 'sketch-planner-project-';
 3→
 4→function getIndex() {
 5→  try {
 6→    const raw = localStorage.getItem(INDEX_KEY);
 7→    return raw ? JSON.parse(raw) : [];
 8→  } catch {
 9→    return [];
10→  }
11→}
12→
13→function saveIndex(index) {
14→  localStorage.setItem(INDEX_KEY, JSON.stringify(index));
15→}
16→
17→export const sketchLocalStorageBackend = {
18→  async save(projectId, name, serialized) {
19→    const key = PROJECT_PREFIX + projectId;
20→    localStorage.setItem(key, JSON.stringify(serialized));
21→
22→    const index = getIndex();
23→    const existing = index.findIndex((p) => p.id === projectId);
24→    const entry = { id: projectId, name, savedAt: serialized.savedAt };
25→
26→    if (existing >= 0) {
27→      index[existing] = entry;
28→    } else {
29→      index.push(entry);
30→    }
31→    saveIndex(index);
32→  },
33→
34→  async load(projectId) {
35→    const key = PROJECT_PREFIX + projectId;
36→    const raw = localStorage.getItem(key);
37→    return raw ? JSON.parse(raw) : null;
38→  },
39→
40→  async list() {
41→    return getIndex();
42→  },
43→
44→  async delete(projectId) {
45→    const key = PROJECT_PREFIX + projectId;
46→    localStorage.removeItem(key);
47→    const index = getIndex().filter((p) => p.id !== projectId);
48→    saveIndex(index);
49→  },
50→};
