  9→function getPartsBounds(parts, view) {
 10→  let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
 11→
 12→  for (const part of parts) {
 13→    if (part.type === 'dimension') continue;
 14→    const { svgX, svgY, svgWidth, svgHeight } = projectPartToView(part, view);
 15→    minX = Math.min(minX, svgX);
 16→    minY = Math.min(minY, svgY);
 17→    maxX = Math.max(maxX, svgX + svgWidth);
 18→    maxY = Math.max(maxY, svgY + svgHeight);
 19→  }
 20→
 21→  if (minX === Infinity) return { x: 0, y: 0, width: 0, height: 0 };
 22→  return { x: minX, y: minY, width: maxX - minX, height: maxY - minY };
 23→}
