 1→import { createDimension } from '../../domain/partModels';
 2→import { viewToModelPosition } from '../../domain/viewProjection';
 3→
 4→export function createDimensionHandler({ dispatch, editorDispatch, activeView }) {
 5→  return {
 6→    onMouseDown(modelPos, e, toolState) {
 7→      if (e.button !== 0) return;
 8→
 9→      if (!toolState.firstPoint) {
10→        // First click - set start point
11→        editorDispatch({
12→          type: 'UPDATE_TOOL_STATE',
13→          payload: {
14→            firstPoint: { x: modelPos.x, y: modelPos.y },
15→          },
16→        });
17→        editorDispatch({
18→          type: 'SET_STATUS_MESSAGE',
19→          message: 'Click second point for dimension.',
20→        });
21→      } else {
22→        // Second click - create dimension
23→        const start3D = viewToModelPosition(toolState.firstPoint.x, toolState.firstPoint.y, activeView);
24→        const end3D = viewToModelPosition(modelPos.x, modelPos.y, activeView);
25→
26→        const dim = createDimension({
27→          startPoint: start3D,
28→          endPoint: end3D,
29→          offset: 200,
30→        });
31→
32→        dispatch({ type: 'PART_ADD', part: dim });
33→
34→        editorDispatch({
35→          type: 'UPDATE_TOOL_STATE',
36→          payload: { firstPoint: null },
37→        });
38→
39→        editorDispatch({
40→          type: 'SET_STATUS_MESSAGE',
41→          message: 'Dimension placed.',
42→        });
43→      }
44→    },
45→
46→    onMouseMove() {},
47→
48→    onMouseUp() {},
49→
50→    onKeyDown(e) {
51→      if (e.key === 'Escape') {
52→        editorDispatch({
53→          type: 'UPDATE_TOOL_STATE',
54→          payload: { firstPoint: null },
55→        });
