247→export function useSketch() {
248→  const ctx = useContext(SketchContext);
249→  if (!ctx) throw new Error('useSketch must be used within SketchProvider');
250→  const { state, dispatch } = ctx;
251→
252→  const getPart = useCallback(
253→    (partId) => state.project.parts.find((p) => p.id === partId) || null,
254→    [state.project.parts]
255→  );
256→
257→  const getAssembly = useCallback(
258→    (assemblyId) => state.project.assemblies.find((a) => a.id === assemblyId) || null,
259→    [state.project.assemblies]
260→  );
261→
262→  const getPartsForAssembly = useCallback(
263→    (assemblyId) => state.project.parts.filter((p) => p.assemblyId === assemblyId),
264→    [state.project.parts]
265→  );
266→
267→  const getChildParts = useCallback(
268→    (parentId) => state.project.parts.filter((p) => p.parentId === parentId),
269→    [state.project.parts]
270→  );
271→
272→  return {
273→    project: state.project,
274→    isDirty: state.isDirty,
275→    canUndo: state.history.length > 0,
276→    canRedo: state.future.length > 0,
277→    dispatch,
278→    getPart,
279→    getAssembly,
280→    getPartsForAssembly,
281→    getChildParts,
282→  };
283→}
