 56→export default function SketchCanvas() {
 57→  const svgRef = useRef(null);
 58→  const isPanning = useRef(false);
 59→  const lastPanPos = useRef({ x: 0, y: 0 });
 60→  const spaceHeld = useRef(false);
 61→  const [cursorPos, setCursorPos] = useState({ x: 0, y: 0 });
 62→
 63→  const { project } = useSketch();
 64→  const {
 65→    activeTool, selectedId, toolState,
 66→    viewport, showGrid, activeView, statusMessage, emptyStateDismissed,
 67→    dispatch: editorDispatch,
 68→  } = useSketchEditor();
 69→
 70→  const tool = useSketchTool();
 71→
 72→  const getModelPos = useCallback((e) => {
 73→    const rect = svgRef.current.getBoundingClientRect();
 74→    return screenToModel(e.clientX, e.clientY, viewport, rect);
 75→  }, [viewport]);
 76→
 77→  const handleMouseDown = useCallback((e) => {
 78→    if (e.button === 1 || (e.button === 0 && spaceHeld.current)) {
 79→      isPanning.current = true;
 80→      lastPanPos.current = { x: e.clientX, y: e.clientY };
 81→      e.preventDefault();
 82→      return;
 83→    }
 84→
 85→    const modelPos = getModelPos(e);
 86→    tool.onMouseDown(modelPos, e, toolState);
 87→  }, [getModelPos, tool, toolState]);
 88→
 89→  const handleMouseMove = useCallback((e) => {
 90→    if (isPanning.current) {
 91→      const dx = e.clientX - lastPanPos.current.x;
 92→      const dy = e.clientY - lastPanPos.current.y;
 93→      editorDispatch({ type: 'PAN', dx, dy });
 94→      lastPanPos.current = { x: e.clientX, y: e.clientY };
 95→      return;
 96→    }
 97→
 98→    const modelPos = getModelPos(e);
 99→    setCursorPos(modelPos);
100→    tool.onMouseMove(modelPos, e, toolState, selectedId);
101→  }, [getModelPos, tool, toolState, selectedId, editorDispatch]);
102→
103→  const handleMouseUp = useCallback((e) => {
104→    if (isPanning.current) {
105→      isPanning.current = false;
106→      return;
107→    }
108→
109→    const modelPos = getModelPos(e);
110→    tool.onMouseUp(modelPos, e, toolState);
111→  }, [getModelPos, tool, toolState]);
112→
113→  const handleWheel = useCallback((e) => {
114→    e.preventDefault();
115→    const rect = svgRef.current.getBoundingClientRect();
116→    const mouseX = e.clientX - rect.left;
117→    const mouseY = e.clientY - rect.top;
118→
119→    const direction = e.deltaY < 0 ? 1 : -1;
120→    const factor = direction > 0 ? SKETCH_ZOOM_FACTOR : 1 / SKETCH_ZOOM_FACTOR;
121→    const newZoom = Math.max(SKETCH_MIN_ZOOM, Math.min(SKETCH_MAX_ZOOM, viewport.zoom * factor));
122→
123→    const newPanX = mouseX - (mouseX - viewport.panX) * (newZoom / viewport.zoom);
124→    const newPanY = mouseY - (mouseY - viewport.panY) * (newZoom / viewport.zoom);
125→
126→    editorDispatch({ type: 'ZOOM', zoom: newZoom, panX: newPanX, panY: newPanY });
127→  }, [viewport, editorDispatch]);
128→
129→  // Keyboard shortcuts
130→  useEffect(() => {
131→    const handleKeyDown = (e) => {
132→      if (e.target.tagName === 'INPUT' || e.target.tagName === 'TEXTAREA' || e.target.isContentEditable) return;
133→
134→      if (e.key === ' ') {
135→        spaceHeld.current = true;
136→        e.preventDefault();
137→        return;
138→      }
139→
140→      if (e.key === 'Escape') {
141→        editorDispatch({ type: 'SET_TOOL', tool: 'select' });
142→        return;
143→      }
144→
145→      if (!e.ctrlKey && !e.metaKey) {
146→        const toolKey = SKETCH_TOOL_SHORTCUTS[e.key.toLowerCase()];
147→        if (toolKey) {
148→          editorDispatch({ type: 'SET_TOOL', tool: toolKey });
149→          return;
150→        }
151→      }
152→
153→      if ((e.key === 'Delete' || e.key === 'Backspace') && selectedId) {
154→        tool.onKeyDown(e, toolState, selectedId);
155→        return;
156→      }
157→
158→      tool.onKeyDown(e, toolState, selectedId);
159→    };
160→
161→    const handleKeyUp = (e) => {
162→      if (e.key === ' ') {
163→        spaceHeld.current = false;
164→      }
165→    };
166→
167→    window.addEventListener('keydown', handleKeyDown);
168→    window.addEventListener('keyup', handleKeyUp);
169→    return () => {
170→      window.removeEventListener('keydown', handleKeyDown);
171→      window.removeEventListener('keyup', handleKeyUp);
172→    };
173→  }, [editorDispatch, selectedId, tool, toolState]);
174→
175→  // Prevent context menu & attach wheel listener
176→  useEffect(() => {
177→    const svg = svgRef.current;
178→    if (!svg) return;
179→    const prevent = (e) => e.preventDefault();
180→    svg.addEventListener('contextmenu', prevent);
181→    svg.addEventListener('wheel', handleWheel, { passive: false });
182→    return () => {
183→      svg.removeEventListener('contextmenu', prevent);
184→      svg.removeEventListener('wheel', handleWheel);
185→    };
186→  }, [handleWheel]);
187→
188→  // Status message auto-clear
189→  useEffect(() => {
190→    if (!statusMessage) return undefined;
191→    const timer = window.setTimeout(() => {
192→      editorDispatch({ type: 'CLEAR_STATUS_MESSAGE' });
193→    }, 2500);
194→    return () => window.clearTimeout(timer);
195→  }, [statusMessage, editorDispatch]);
196→
197→  const cursor = spaceHeld.current ? 'grab' : tool.getCursor(toolState);
198→  const zoomPercent = Math.round(viewport.zoom * 1000);
199→
200→  // Check if project is empty for the empty-state overlay
201→  const hasParts = project.parts.length > 0;
202→  const hasAssemblies = project.assemblies.length > 0;
203→  const showEmptyState = !hasParts && !hasAssemblies && !emptyStateDismissed;
204→
205→  // Split parts from dimensions
206→  const renderParts = project.parts.filter((p) => p.type !== 'dimension');
207→  const dimensions = project.parts.filter((p) => p.type === 'dimension');
208→
209→  // Drag preview for part placement
210→  const drawPreview = toolState.drawing && toolState.startPos && toolState.currentPos
211→    ? {
212→        x: Math.min(toolState.startPos.x, toolState.currentPos.x),
213→        y: Math.min(toolState.startPos.y, toolState.currentPos.y),
214→        width: Math.abs(toolState.currentPos.x - toolState.startPos.x),
215→        height: Math.abs(toolState.currentPos.y - toolState.startPos.y),
216→      }
217→    : null;
218→
219→  // Dimension first-click indicator
220→  const dimFirstClick = activeTool === 'dimension' && toolState.firstPoint;
221→
222→  // Compute XYZ from cursor position using inverse projection
223→  const modelXYZ = viewToModelPosition(cursorPos.x, cursorPos.y, activeView);
224→
225→  return (
226→    <div className={styles.canvasContainer}>
227→      <svg
228→        ref={svgRef}
229→        className={styles.svg}
230→        style={{ cursor }}
231→        onPointerDown={handleMouseDown}
232→        onPointerMove={handleMouseMove}
233→        onPointerUp={handleMouseUp}
234→      >
235→        <g transform={`translate(${viewport.panX}, ${viewport.panY}) scale(${viewport.zoom})`}>
236→          {showGrid && <GridRenderer />}
237→
238→          {/* Canvas boundary indicator */}
239→          <rect
240→            x={0}
241→            y={0}
242→            width={project.canvasWidth}
243→            height={project.canvasHeight}
244→            fill="none"
245→            stroke="var(--color-border)"
246→            strokeWidth={2}
247→            vectorEffect="non-scaling-stroke"
248→            strokeDasharray="8 4"
249→            style={{ pointerEvents: 'none' }}
250→          />
251→
252→          {/* Rendered parts */}
253→          {renderParts.map((part) => (
254→            <PartRenderer
255→              key={part.id}
256→              part={part}
257→              view={activeView}
258→              isSelected={part.id === selectedId}
259→              zoom={viewport.zoom}
260→            />
261→          ))}
262→
263→          {/* Dimension annotations */}
264→          {dimensions.map((dim) => (
265→            <DimensionRenderer
266→              key={dim.id}
267→              dimension={dim}
268→              view={activeView}
269→              zoom={viewport.zoom}
270→            />
271→          ))}
272→
273→          {/* Draw preview */}
274→          {drawPreview && (
275→            <rect
276→              x={drawPreview.x}
277→              y={drawPreview.y}
278→              width={drawPreview.width}
279→              height={drawPreview.height}
280→              fill="none"
281→              stroke="var(--color-workspace-sketch, #B8860B)"
282→              strokeWidth={2}
283→              vectorEffect="non-scaling-stroke"
284→              strokeDasharray="6 3"
285→              style={{ pointerEvents: 'none' }}
286→            />
287→          )}
288→
289→          {/* Dimension first-click indicator */}
290→          {dimFirstClick && (
291→            <circle
292→              cx={toolState.firstPoint.x}
293→              cy={toolState.firstPoint.y}
294→              r={5 / viewport.zoom}
295→              fill="var(--color-workspace-sketch, #B8860B)"
296→              style={{ pointerEvents: 'none' }}
297→            />
298→          )}
299→        </g>
300→      </svg>
301→
302→      {/* Empty-state overlay */}
303→      {showEmptyState && <SketchEmptyState />}
304→
305→      {/* Status bar */}
306→      <div className={styles.statusBar} role="status" aria-live="polite">
307→        <span className={styles.statusContext}>{getViewLabel(activeView)}</span>
308→        <span className={styles.statusCoords}>X: {Math.round(modelXYZ.x)} mm</span>
309→        <span className={styles.statusCoords}>Y: {Math.round(modelXYZ.y)} mm</span>
310→        <span className={styles.statusCoords}>Z: {Math.round(modelXYZ.z)} mm</span>
311→        <span className={styles.statusContext}>Zoom: {zoomPercent}%</span>
312→        <span className={styles.statusTool}>{activeTool}</span>
313→      </div>
314→
315→      {/* Toast notifications */}
316→      {statusMessage && (
317→        <div className={styles.toast}>
318→          {statusMessage}
319→          <div className={styles.toastProgress} />
320→        </div>
321→      )}
322→    </div>
323→  );
324→}
