 1→export function sketchDeserialize(json) {
 2→  if (!json || json.schemaType !== 'sketch') {
 3→    throw new Error('Invalid sketch project data: missing or wrong schemaType');
 4→  }
 5→
 6→  const project = json.data;
 7→  if (!project || !project.id || !project.name) {
 8→    throw new Error('Invalid sketch project data: missing required fields');
 9→  }
10→
11→  // Ensure arrays exist
12→  project.parts = project.parts || [];
13→  project.assemblies = project.assemblies || [];
14→  project.annotations = project.annotations || [];
15→  project.sheets = project.sheets || [];
16→
17→  return {
18→    project,
19→    savedAt: json.savedAt,
20→  };
21→}
