131→export default function SketchPropertiesPanel() {
132→  const { getPart, dispatch, project } = useSketch();
133→  const { selectedId } = useSketchEditor();
134→
135→  const part = selectedId ? getPart(selectedId) : null;
136→
137→  if (!part || part.type === 'dimension') {
138→    return (
139→      <div className={styles.panel}>
140→        <div className={styles.header}>Properties</div>
141→        <div className={styles.empty}>Select a part to view its properties</div>
142→      </div>
143→    );
144→  }
145→
146→  const handleUpdate = (changes) => {
147→    dispatch({ type: 'PART_UPDATE', part: { id: part.id, ...changes } });
148→  };
149→
150→  const handlePositionUpdate = (posChanges) => {
151→    dispatch({ type: 'PART_UPDATE', part: { id: part.id, position: { ...part.position, ...posChanges } } });
152→  };
153→
154→  const DimensionFields = dimensionFields[part.type];
155→
156→  // Find assembly this part belongs to
157→  const assembly = part.assemblyId
158→    ? project.assemblies.find((a) => a.id === part.assemblyId)
159→    : null;
160→
161→  return (
162→    <div className={styles.panel}>
163→      <div className={styles.header}>Properties</div>
164→
165→      <div className={styles.content}>
166→        {/* Name */}
167→        <TextInput label="Name" value={part.name} onChange={(v) => handleUpdate({ name: v })} />
168→
169→        {/* Type badge */}
170→        <div className={styles.field}>
171→          <span className={styles.fieldLabel}>Type</span>
172→          <span className={styles.typeBadge}>{part.type}</span>
173→        </div>
174→
175→        {/* Position */}
176→        <PositionSection position={part.position} onUpdate={handlePositionUpdate} />
177→
178→        {/* Type-specific dimensions */}
179→        {DimensionFields && (
180→          <div className={styles.fieldGroup}>
181→            <span className={styles.groupTitle}>Dimensions</span>
182→            <DimensionFields part={part} onUpdate={handleUpdate} />
183→          </div>
184→        )}
185→
186→        {/* Style */}
187→        <div className={styles.fieldGroup}>
188→          <span className={styles.groupTitle}>Style</span>
189→          <label className={styles.field}>
190→            <span className={styles.fieldLabel}>Fill</span>
191→            <input
192→              type="color"
193→              value={part.fill === 'none' ? '#ffffff' : part.fill}
194→              onChange={(e) => handleUpdate({ fill: e.target.value })}
195→              className={styles.colorInput}
196→            />
197→          </label>
198→          <label className={styles.field}>
199→            <span className={styles.fieldLabel}>Stroke</span>
200→            <input
201→              type="color"
202→              value={part.stroke || '#1E2433'}
203→              onChange={(e) => handleUpdate({ stroke: e.target.value })}
204→              className={styles.colorInput}
205→            />
206→          </label>
207→        </div>
208→
209→        {/* Assembly */}
210→        <div className={styles.fieldGroup}>
211→          <span className={styles.groupTitle}>Assembly</span>
212→          <div className={styles.field}>
213→            <span className={styles.fieldLabel}>{assembly ? assembly.name : 'None'}</span>
214→          </div>
215→        </div>
216→      </div>
217→    </div>
218→  );
219→}
