 45→export default function SketchSidebar() {
 46→  const { project, dispatch, getPartsForAssembly } = useSketch();
 47→  const { activeAssemblyId, selectedId, dispatch: editorDispatch } = useSketchEditor();
 48→
 49→  const assemblies = project.assemblies || [];
 50→  const parts = project.parts.filter((p) => p.type !== 'dimension');
 51→
 52→  // Show parts filtered by active assembly, or all parts if none selected
 53→  const visibleParts = activeAssemblyId
 54→    ? parts.filter((p) => p.assemblyId === activeAssemblyId)
 55→    : parts;
 56→
 57→  const handleAddAssembly = () => {
 58→    const asm = createAssembly(`Assembly ${assemblies.length + 1}`);
 59→    dispatch({ type: 'ASSEMBLY_ADD', assembly: asm });
 60→    editorDispatch({ type: 'SET_ACTIVE_ASSEMBLY', assemblyId: asm.id });
 61→  };
 62→
 63→  const handleSelectAssembly = (assemblyId) => {
 64→    editorDispatch({
 65→      type: 'SET_ACTIVE_ASSEMBLY',
 66→      assemblyId: activeAssemblyId === assemblyId ? null : assemblyId,
 67→    });
 68→  };
 69→
 70→  const handleDeleteAssembly = (e, assemblyId) => {
 71→    e.stopPropagation();
 72→    dispatch({ type: 'ASSEMBLY_DELETE', assemblyId });
 73→    if (activeAssemblyId === assemblyId) {
 74→      editorDispatch({ type: 'SET_ACTIVE_ASSEMBLY', assemblyId: null });
 75→    }
 76→  };
 77→
 78→  const handleSelectPart = (partId) => {
 79→    editorDispatch({ type: 'SELECT_OBJECT', id: partId, objectType: 'part' });
 80→  };
 81→
 82→  const handleDeletePart = (e, partId) => {
 83→    e.stopPropagation();
 84→    dispatch({ type: 'PART_DELETE', partId });
 85→    if (selectedId === partId) {
 86→      editorDispatch({ type: 'DESELECT' });
 87→    }
 88→  };
 89→
 90→  return (
 91→    <div className={styles.sidebar}>
 92→      {/* Assemblies panel */}
 93→      <div className={styles.section}>
 94→        <div className={styles.sectionHeaderRow}>
 95→          <span className={styles.sectionTitle}>Assemblies</span>
 96→          <span className={styles.count}>{assemblies.length}</span>
 97→          <button className={styles.addBtn} onClick={handleAddAssembly} aria-label="Add Assembly" title="Add Assembly">+</button>
 98→        </div>
 99→
100→        <div className={styles.layerList}>
101→          {assemblies.map((asm) => {
102→            const isActive = asm.id === activeAssemblyId;
103→            const partCount = getPartsForAssembly(asm.id).length;
104→
105→            return (
106→              <div
107→                key={asm.id}
108→                className={`${styles.layerItem} ${isActive ? styles.layerItemActive : ''}`}
109→                onClick={() => handleSelectAssembly(asm.id)}
110→                role="button"
111→                tabIndex={0}
112→                onKeyDown={(e) => {
113→                  if (e.key === 'Enter' || e.key === ' ') {
114→                    e.preventDefault();
115→                    handleSelectAssembly(asm.id);
116→                  }
117→                }}
118→              >
119→                <div className={styles.layerInfo}>
120→                  <AssemblyIcon />
121→                  <span className={styles.layerName}>{asm.name}</span>
122→                  {partCount > 0 && <span className={styles.shapeCount}>{partCount}</span>}
123→                </div>
124→                <div className={styles.layerActions}>
125→                  <button
126→                    className={styles.layerActionBtn}
127→                    onClick={(e) => handleDeleteAssembly(e, asm.id)}
128→                    aria-label="Delete Assembly"
129→                    title="Delete Assembly"
130→                  >
131→                    <TrashIcon />
132→                  </button>
133→                </div>
134→              </div>
135→            );
136→          })}
137→        </div>
138→      </div>
139→
140→      {/* Parts panel */}
141→      <div className={styles.section}>
142→        <div className={styles.sectionHeaderRow}>
143→          <span className={styles.sectionTitle}>
144→            Parts{activeAssemblyId ? ' (filtered)' : ''}
145→          </span>
146→          <span className={styles.count}>{visibleParts.length}</span>
147→        </div>
148→
149→        <div className={styles.layerList}>
150→          {visibleParts.map((part) => {
151→            const isSelected = part.id === selectedId;
152→
153→            return (
154→              <div
155→                key={part.id}
156→                className={`${styles.layerItem} ${isSelected ? styles.layerItemActive : ''}`}
157→                onClick={() => handleSelectPart(part.id)}
158→                role="button"
159→                tabIndex={0}
160→                onKeyDown={(e) => {
161→                  if (e.key === 'Enter' || e.key === ' ') {
162→                    e.preventDefault();
163→                    handleSelectPart(part.id);
164→                  }
165→                }}
166→              >
167→                <div className={styles.layerInfo}>
168→                  <TypeBadge type={part.type} />
169→                  <span className={styles.layerName}>{part.name}</span>
170→                </div>
171→                <div className={styles.layerActions}>
172→                  <button
173→                    className={styles.layerActionBtn}
174→                    onClick={(e) => handleDeletePart(e, part.id)}
175→                    aria-label="Delete Part"
176→                    title="Delete Part"
177→                  >
178→                    <TrashIcon />
179→                  </button>
180→                </div>
181→              </div>
182→            );
183→          })}
184→        </div>
185→      </div>
186→    </div>
187→  );
188→}
