  1→import { createContext, useContext, useReducer, useCallback } from 'react';
  2→import { createSketchProject } from '../domain/sketchModels';
  3→
  4→const SketchContext = createContext(null);
  5→const HISTORY_LIMIT = 80;
  6→
  7→function snapshotSketch(sketchProject) {
  8→  return JSON.stringify(sketchProject);
  9→}
 10→
 11→function applyUpdate(state, nextProject, recordHistory = true) {
 12→  const nextSnapshot = snapshotSketch(nextProject);
 13→  const history = recordHistory
 14→    ? [...state.history, state.project].slice(-HISTORY_LIMIT)
 15→    : state.history;
 16→
 17→  return {
 18→    ...state,
 19→    history,
 20→    future: recordHistory ? [] : state.future,
 21→    project: nextProject,
 22→    isDirty: nextSnapshot !== state.savedSnapshot,
 23→  };
 24→}
 25→
 26→function mergePart(existing, updates) {
 27→  const merged = { ...existing, ...updates };
 28→  // Deep-merge position and rotation
 29→  if (updates.position) {
 30→    merged.position = { ...existing.position, ...updates.position };
 31→  }
 32→  if (updates.rotation) {
 33→    merged.rotation = { ...existing.rotation, ...updates.rotation };
 34→  }
 35→  return merged;
 36→}
 37→
 38→function sketchReducer(state, action) {
 39→  switch (action.type) {
 40→    case 'SKETCH_NEW': {
 41→      const newProject = action.project || createSketchProject();
 42→      return {
 43→        project: newProject,
 44→        isDirty: false,
 45→        savedSnapshot: snapshotSketch(newProject),
 46→        history: [],
 47→        future: [],
 48→      };
 49→    }
 50→
 51→    case 'SKETCH_LOAD': {
 52→      const loaded = action.project;
 53→      return {
 54→        project: loaded,
 55→        isDirty: false,
 56→        savedSnapshot: snapshotSketch(loaded),
 57→        history: [],
 58→        future: [],
 59→      };
 60→    }
 61→
 62→    case 'PART_ADD':
 63→      return applyUpdate(state, {
 64→        ...state.project,
 65→        updatedAt: new Date().toISOString(),
 66→        parts: [...state.project.parts, action.part],
 67→      });
 68→
 69→    case 'PART_UPDATE':
 70→      return applyUpdate(state, {
 71→        ...state.project,
 72→        updatedAt: new Date().toISOString(),
 73→        parts: state.project.parts.map((p) =>
 74→          p.id === action.part.id ? mergePart(p, action.part) : p
 75→        ),
 76→      });
 77→
 78→    case 'PART_DELETE': {
 79→      const partId = action.partId;
 80→      // Also remove child parts (cutouts/holes with this parentId)
 81→      const childIds = new Set(
 82→        state.project.parts.filter((p) => p.parentId === partId).map((p) => p.id)
 83→      );
 84→      const idsToRemove = new Set([partId, ...childIds]);
 85→
 86→      return applyUpdate(state, {
 87→        ...state.project,
 88→        updatedAt: new Date().toISOString(),
 89→        parts: state.project.parts.filter((p) => !idsToRemove.has(p.id)),
 90→        assemblies: state.project.assemblies.map((asm) => ({
 91→          ...asm,
 92→          partIds: asm.partIds.filter((id) => !idsToRemove.has(id)),
 93→        })),
 94→      });
 95→    }
 96→
 97→    case 'ASSEMBLY_ADD':
 98→      return applyUpdate(state, {
 99→        ...state.project,
100→        updatedAt: new Date().toISOString(),
101→        assemblies: [...state.project.assemblies, action.assembly],
102→      });
103→
104→    case 'ASSEMBLY_UPDATE':
105→      return applyUpdate(state, {
106→        ...state.project,
107→        updatedAt: new Date().toISOString(),
108→        assemblies: state.project.assemblies.map((asm) =>
109→          asm.id === action.assembly.id ? { ...asm, ...action.assembly } : asm
110→        ),
111→      });
112→
113→    case 'ASSEMBLY_DELETE': {
114→      const asmId = action.assemblyId;
115→      return applyUpdate(state, {
116→        ...state.project,
117→        updatedAt: new Date().toISOString(),
118→        assemblies: state.project.assemblies.filter((asm) => asm.id !== asmId),
119→        parts: state.project.parts.map((p) =>
120→          p.assemblyId === asmId ? { ...p, assemblyId: null } : p
121→        ),
122→      });
123→    }
124→
125→    case 'ASSEMBLY_ADD_PART': {
126→      const { assemblyId, partId } = action;
127→      return applyUpdate(state, {
128→        ...state.project,
129→        updatedAt: new Date().toISOString(),
130→        assemblies: state.project.assemblies.map((asm) =>
131→          asm.id === assemblyId && !asm.partIds.includes(partId)
132→            ? { ...asm, partIds: [...asm.partIds, partId] }
133→            : asm
134→        ),
135→        parts: state.project.parts.map((p) =>
136→          p.id === partId ? { ...p, assemblyId } : p
137→        ),
138→      });
139→    }
140→
141→    case 'ASSEMBLY_REMOVE_PART': {
142→      const { assemblyId, partId } = action;
143→      return applyUpdate(state, {
144→        ...state.project,
145→        updatedAt: new Date().toISOString(),
146→        assemblies: state.project.assemblies.map((asm) =>
147→          asm.id === assemblyId
148→            ? { ...asm, partIds: asm.partIds.filter((id) => id !== partId) }
149→            : asm
150→        ),
151→        parts: state.project.parts.map((p) =>
152→          p.id === partId && p.assemblyId === assemblyId ? { ...p, assemblyId: null } : p
153→        ),
154→      });
155→    }
156→
157→    case 'ANNOTATION_ADD':
158→      return applyUpdate(state, {
159→        ...state.project,
160→        updatedAt: new Date().toISOString(),
161→        annotations: [...(state.project.annotations || []), action.annotation],
162→      });
163→
164→    case 'ANNOTATION_UPDATE':
165→      return applyUpdate(state, {
166→        ...state.project,
167→        updatedAt: new Date().toISOString(),
168→        annotations: (state.project.annotations || []).map((a) =>
169→          a.id === action.annotation.id ? { ...a, ...action.annotation } : a
170→        ),
171→      });
172→
173→    case 'ANNOTATION_DELETE':
174→      return applyUpdate(state, {
175→        ...state.project,
176→        updatedAt: new Date().toISOString(),
177→        annotations: (state.project.annotations || []).filter((a) => a.id !== action.annotationId),
178→      });
179→
180→    case 'PROJECT_UPDATE_META':
181→      return applyUpdate(state, {
182→        ...state.project,
183→        updatedAt: new Date().toISOString(),
184→        ...action.meta,
185→      });
186→
187→    case 'UNDO': {
188→      if (state.history.length === 0) return state;
189→      const previous = state.history[state.history.length - 1];
190→      return {
191→        ...state,
192→        project: previous,
193→        history: state.history.slice(0, -1),
194→        future: [state.project, ...state.future].slice(0, HISTORY_LIMIT),
195→        isDirty: snapshotSketch(previous) !== state.savedSnapshot,
196→      };
197→    }
198→
199→    case 'REDO': {
200→      if (state.future.length === 0) return state;
201→      const next = state.future[0];
202→      return {
203→        ...state,
204→        project: next,
205→        history: [...state.history, state.project].slice(-HISTORY_LIMIT),
206→        future: state.future.slice(1),
207→        isDirty: snapshotSketch(next) !== state.savedSnapshot,
208→      };
209→    }
210→
211→    case 'MARK_SAVED':
212→      return {
213→        ...state,
214→        isDirty: false,
215→        savedSnapshot: snapshotSketch(state.project),
216→      };
217→
218→    default:
219→      return state;
220→  }
221→}
222→
223→function createInitialState(project) {
224→  return {
225→    project,
226→    isDirty: false,
227→    savedSnapshot: snapshotSketch(project),
228→    history: [],
229→    future: [],
230→  };
231→}
232→
233→export function SketchProvider({ children, initialProject }) {
234→  const [state, dispatch] = useReducer(
235→    sketchReducer,
236→    initialProject || createSketchProject(),
237→    createInitialState
238→  );
239→
240→  return (
241→    <SketchContext.Provider value={{ state, dispatch }}>
242→      {children}
243→    </SketchContext.Provider>
244→  );
245→}
246→
247→export function useSketch() {
248→  const ctx = useContext(SketchContext);
249→  if (!ctx) throw new Error('useSketch must be used within SketchProvider');
250→  const { state, dispatch } = ctx;
251→
252→  const getPart = useCallback(
253→    (partId) => state.project.parts.find((p) => p.id === partId) || null,
254→    [state.project.parts]
255→  );
256→
257→  const getAssembly = useCallback(
258→    (assemblyId) => state.project.assemblies.find((a) => a.id === assemblyId) || null,
259→    [state.project.assemblies]
260→  );
261→
262→  const getPartsForAssembly = useCallback(
263→    (assemblyId) => state.project.parts.filter((p) => p.assemblyId === assemblyId),
264→    [state.project.parts]
265→  );
266→
267→  const getChildParts = useCallback(
268→    (parentId) => state.project.parts.filter((p) => p.parentId === parentId),
269→    [state.project.parts]
270→  );
271→
272→  return {
273→    project: state.project,
274→    isDirty: state.isDirty,
275→    canUndo: state.history.length > 0,
276→    canRedo: state.future.length > 0,
277→    dispatch,
278→    getPart,
279→    getAssembly,
280→    getPartsForAssembly,
281→    getChildParts,
282→  };
283→}
